def move_robot(grid, robot, boxes):
    x, y = robot
    for move in moves:
        dx, dy = DIRECTIONS[move]
        new_x, new_y = x + dx, y + dy
        next_x, next_y = new_x, new_y

        if not in_bounds(new_x, new_y, grid):
            continue

        if grid[new_x][new_y] == '#':
            continue

        box_list = []
        while (new_x, new_y) in boxes:
            box_list.append((new_x, new_y))
            new_x += dx
