        if grid[new_x][new_y] == '#' or (new_x, new_y) in boxes:
            continue

        for box in box_list[::-1]:
            boxes.remove(box)
            bx = box[0] + dx
            by = box[1] + dy
            boxes.add((bx, by))

        x, y = next_x, next_y

    return boxes

