def move_boxes(robot, moves, grid):
    for move in moves:
        i, j = robot
        if move == '<':
            k = j-1
            while grid[i][k] == ']':
                k -= 2
            if grid[i][k] == '.':
                for b in range(k, j):
                    grid[i][b] = grid[i][b+1]
                new_robot = (i, j-1)

        elif move == '>':
            k = j+1
            while grid[i][k] == '[':
                k += 2
            if grid[i][k] == '.':
                for b in range(k, j, -1):
                    grid[i][b] = grid[i][b-1]
                new_robot = (i, j+1)

        elif move == '^':
            queue = {(i-1, j)}
            rows = defaultdict(set)
            blocked = False
            while queue and not blocked:
                x, y = queue.pop()
                cur = grid[x][y]
                if cur == '#':
                    blocked = True
                elif cur == ']':
                    rows[x].update({y-1, y})
                    queue.update({(x-1, y), (x-1, y-1)})
                elif cur == '[':
                    rows[x].update({y, y+1})
                    queue.update({(x-1, y), (x-1, y+1)})
                else:
                    rows[x].add(y)

            if not blocked:
                for x in sorted(rows):
                    for y in rows[x]:
                        if y in rows[x+1]:
                            grid[x][y] = grid[x+1][y]
                        else:
                            grid[x][y] = '.'
                new_robot = (i-1, j)

        elif move == 'v':
            queue = {(i+1, j)}
            rows = defaultdict(set)
            blocked = False

            while queue and not blocked:
                x, y = queue.pop()
                cur = grid[x][y]
                if cur == '#':
                    blocked = True
                elif cur == ']':
                    rows[x].update({y-1, y})
                    queue.update({(x+1, y), (x+1, y-1)})
                elif cur == '[':
                    rows[x].update({y, y+1})
                    queue.update({(x+1, y), (x+1, y+1)})
                else:
                    rows[x].add(y)

            if not blocked:
                for x in sorted(rows, reverse=True):
                    for y in rows[x]:
                        if y in rows[x-1]:
                            grid[x][y] = grid[x-1][y]
                        else:
                            grid[x][y] = '.'
                new_robot = (i+1, j)

        robot = new_robot

    boxes = set()

    for i in range(len(grid)):
        for j in range(len(grid[i])):
            if grid[i][j] == '[':
                boxes.add((i, j))

    return boxes

