def run_prog(regs, prog):
    i = 0
    output = []
    while i < len(prog):
        op = prog[i]
        i += 1

        literal_op = prog[i]
        i += 1
        if literal_op > 3:
            combo = regs[chr(ord('A')  + literal_op - 4)]
        else:
            combo = literal_op

        if op == 0:
            regs['A'] = regs['A'] >> combo
        elif op == 1:
            regs['B'] = regs['B'] ^ literal_op
        elif op == 2:
            regs['B'] = combo % 8
        elif op == 3:
            if regs['A'] != 0:
                i = literal_op
        elif op == 4:
            regs['B'] = regs['C'] ^ regs['B']
        elif op == 5:
            output.append(combo % 8)
        elif op == 6:
            regs['B'] = regs['A'] >> combo
        elif op == 7:
            regs['C'] = regs['A'] >> combo
    return output

def run_with_a(regs, prog, a):
    nr = dict(regs)
    nr['A'] = a
    return run_prog(nr, prog)

def brute(regs, prog, wanted_out):
    nxt = deque([])
    for a in range(2**9):
        nxt.append((9, a))
    while nxt:
