@cache
def quantifyStrokes(code):
    curr = arrows_dict['A']
    total = 0
    for x in code:
        coords = arrows_dict[x]
        total += abs(coords[0] - curr[0]) + abs(coords[1] - curr[1]) + 1
        curr = coords
    return total


# Function for recursive keystroke calculation on arrows keypad
@cache
def numPadKeystrokes(code, recurse):
    if recurse == 0:
        return quantifyStrokes(code)
    curr = arrows_dict['A']
    avoidPad = arrows_dict[' ']
    totalNum = 0
    for x in code:
        coords = arrows_dict[x]
        dy = coords[0] - curr[0]
        dx = coords[1] - curr[1]
        s = 'v' * dy if dy > 0 else '^' * (-dy)
        s += '>' * dx if dx > 0 else '<' * (-dx)
        min_keystrokes = float('inf')
        for p in permutations(s):
            n = curr
            for char in p:
                if char == 'v':
                    n = (n[0] + 1, n[1])
                elif char == '^':
                    n = (n[0] - 1, n[1])
                elif char == '>':
                    n = (n[0], n[1] + 1)
                elif char == '<':
                    n = (n[0], n[1] - 1)
                if n == avoidPad:
