            if n == avoidPad:
                continue
            # recursive call on numPadKeystrokes
            min_keystrokes = min(numPadKeystrokes(''.join(p) + 'A', recurse - 1), min_keystrokes)
        curr = coords
        totalNum += min_keystrokes
    return totalNum


