def solver(design, patterns):
    patterns = set(patterns)
    n = len(design)
    dp = {0: 1}  # Base case: one way to form an empty string

    for i in range(1, n + 1):
        dp[i] = 0
        for j in range(i):
            # Check if the substring design[j:i] is in the set of patterns
            if design[j:i] in patterns:
                dp[i] += dp[j]
    return dp[n]


