def mazeTraverse(pts):
    start = (0, 0)
    end = (70, 70)

    seen = set()
    q = [(start, 0)]

    while q:
        cPos, cDir = q.pop(0)

        if cPos in seen:
            continue

        if cPos == end:
            return cDir

        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            np = cPos[0] + dx, cPos[1] + dy
            if 0 <= np[0] <= 70 and 0 <= np[1] <= 70 and np not in seen and np not in pts:
                q.append((np, cDir + 1))

        seen.add(cPos)

    return None


