#!/usr/bin/env python3

import sys
from collections import defaultdict, deque

def build_graph(rules):
    graph = defaultdict(list)

    for rule in rules:
        x, y = map(int, rule.split("|"))

        graph[x].append(y)

    return graph


def is_valid_update(update, graph):
    subgraph = defaultdict(list)
    for x in update:
        subgraph[x] = [y for y in graph[x] if y in update]

    in_degree = {x: 0 for x in update}
    for x in subgraph:
        for y in subgraph[x]:
            in_degree[y] += 1

    queue = deque([x for x in update if in_degree[x] == 0])
    sorted_order = []
    while queue:
        node = queue.popleft()
        sorted_order.append(node)
        for neighbor in subgraph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # Check if sorted_order matches the update
    return sorted_order == update


def reorder_update(update, graph):
    subgraph = defaultdict(list)
    for x in update:
        subgraph[x] = [y for y in graph[x] if y in update]

    in_degree = {x: 0 for x in update}
    for x in subgraph:
        for y in subgraph[x]:
            in_degree[y] += 1

    queue = deque([x for x in update if in_degree[x] == 0])
    sorted_order = []
    while queue:
        node = queue.popleft()
        sorted_order.append(node)
        for neighbor in subgraph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    return sorted_order


