        if ins[0] == "inp":
            self.vars[ins[1]] = self.input.pop()
        if ins[0] == "add":
            self.vars[ins[1]] += self.var(ins[2])
        if ins[0] == "mul":
            self.vars[ins[1]] *= self.var(ins[2])
        if ins[0] == "div":
            self.vars[ins[1]] //= self.var(ins[2])
        if ins[0] == "mod":
            self.vars[ins[1]] %= self.var(ins[2])
        if ins[0] == "eql":
            self.vars[ins[1]] = 1 if self.vars[ins[1]] == self.var(ins[2]) else 0


