    n = 0
    for i in bits:
        n <<= 1
        n += i
    return n


def decipher_package(bits):
    global V
    V += num(take(3, bits))
    t = num(take(3, bits))

    if t == 4:
        first_bit = 1
        n = []
        while first_bit:
            first_bit = num(take(1, bits))
