def is_safe(nums):
    if len(set(nums)) != len(nums):
        return False
    diffs = [b - a for a, b in zip(nums[:-1], nums[1:])]

    incdec = all(d > 0 for d in diffs) or all(d < 0 for d in diffs)
    limits = all(1 <= abs(d) <= 3 for d in diffs)

