def make_move(grid, pos, d):
    r, c = pos
    dr = {"^": -1, "v": 1}.get(d, 0)
    dc = {"<": -1, ">": 1}.get(d, 0)
    targets = [(r, c)]

    for cr, cc in targets:
        nr, nc = cr + dr, cc + dc
        if (nr, nc) in targets:
            continue
        char = grid[nr][nc]
        if char == "#":
            return grid, pos
        if char == "[":
            targets.extend([(nr, nc), (nr, nc + 1)])
        if char == "]":
            targets.extend([(nr, nc), (nr, nc - 1)])

    new_grid = [row.copy() for row in grid]
    new_grid[r][c] = "."
    new_grid[r + dr][c + dc] = "@"
    for br, bc in targets[1:]:
        new_grid[br][bc] = "."
    for br, bc in targets[1:]:
        new_grid[br + dr][bc + dc] = grid[br][bc]

    return new_grid, (r + dr, c + dc)


