def find_file_spans(blocks):
    spans = {}
    i = 0
    while i < len(blocks):
        if blocks[i] is not None:
            start = i
            file_id = blocks[i]
            length = 0
            while i < len(blocks) and blocks[i] == file_id:
                length += 1
                i += 1
            spans[file_id] = (start, length)
        else:
