    data += 1
    newflashes = data > 9
    oldflashes = data > 9

    while np.any(newflashes):
        for idx in (idx for idx in np.ndindex(data.shape) if newflashes[idx]):
            for n in get_neighbhours(idx, data.shape):
                data[n] += 1

        newflashes = (data > 9) ^ oldflashes
        oldflashes = data > 9

    data *= data <= 9
    return np.sum(data == 0)


