MATCHING = {"(": ")", "[": "]", "{": "}", "<": ">"}
SYNTAX_ERROR_VALUE = {")": 3, "]": 57, "}": 1197, ">": 25137}
COMPLETION_VALUE = {")": 1, "]": 2, "}": 3, ">": 4}


