def find_error(x):
    stack = []
    for c in x:
        if c in "([{<":
            stack.append(c)
        elif c in ")]}>":
            prev = stack.pop()
            if c != MATCHING[prev]:
                return c
    return stack


def get_completion_vals(x):
    stack = find_error(x)
    if isinstance(stack, str):
        return

    return (COMPLETION_VALUE[MATCHING[x]] for x in reversed(stack))


def syntax_error(x):
    return SYNTAX_ERROR_VALUE[x] if not isinstance(x, list) else 0


