    return new_pos, total


def merge_space(memory):
    i = 0
    last_space_i = None
    cumul_memory = 0
    while i < len(memory):
        amount, id, is_file = memory[i]
        if is_file:
            if last_space_i is not None:
                memory[last_space_i] = (cumul_memory, 0, False)
                while i > last_space_i + 1:
                    i -= 1
                    memory.pop(i)
                last_space_i = None
        else:
            if last_space_i is None:
                last_space_i = i
                cumul_memory = amount
            else:
                cumul_memory += amount
        i += 1



