def eval_func(func, vals):
    arg1, op, arg2 = func
    if op == "AND":
        return vals[arg1] * vals[arg2]
    elif op == "OR":
        return vals[arg1] | vals[arg2]
    elif op == "XOR":
        return vals[arg1] ^ vals[arg2]


def recurse_eval(out, funcs, vals):
    arg1, op, arg2 = funcs[out]
    if arg1 not in vals:
        recurse_eval(arg1, funcs, vals)
    if arg2 not in vals:
