class PackDec:
    def __init__(self, s):
        self.vals = list(s)
        self.buffer = ""
        self.i = 0 # next to add to buffer

    def get(self, n):
        r = ""
        while n > 0:
            a = self.buffer[:n]
            self.buffer = self.buffer[n:]
            r += a
            n -= len(a)
            if len(self.buffer) == 0:
                self.i += 1
                self.buffer = bin(16 + int(self.vals[self.i - 1],16))[3:]
        return r

    def align(self):
        if len(self.buffer) < 4:
            self.buffer = ""

class BitsOnly:
    def __init__(self, s):
        self.s = s

    def get(self, n):
        a, self.s = self.s[:n], self.s[n:]
        return a

global version_sum
