pd = PackDec(s)

def parse(pd):
    global version_sum
    version = int(pd.get(3),2)
    typeid = int(pd.get(3),2)
    version_sum += version

    if typeid == 4: #literal
        leadbit = pd.get(1)
        value = pd.get(4)
        while leadbit == "1":
            leadbit = pd.get(1)
            value += pd.get(4)
        return int(value, 2)
