from typing import List

def part1(moves : List[str]) -> int:
	''' Solve part 1. '''
	x = y = 0
	for move in moves:
		direction, magnitude = move.split()
		magnitude = int(magnitude)

		if direction == 'forward':
			x += magnitude
		elif direction == 'down':
			y += magnitude
		elif direction == 'up':
			y = max(0, y - magnitude)

	return x * y

def part2(moves : List[str]) -> int:
	''' Solve part 2. '''
	x = y = aim = 0
	for move in moves:
		direction, magnitude = move.split()
		magnitude = int(magnitude)

		if direction == 'forward':
			x += magnitude
			y += aim * magnitude
		elif direction == 'down':
			aim += magnitude
		elif direction == 'up':
			aim -= magnitude

	return x * y

