@cache
def multi_enhance(ox,oy,depth):
    if depth == 0: return '01'[(ox,oy) in LIT_PIXELS]
    new = []
    for y in range(oy-1,oy+2):
        for x in range(ox-1,ox+2):
            new.append(multi_enhance(x,y,depth-1))
    return ENHANCE_ALGO[int("".join(new),2)]

