def irange(a,b):
    """Inclusive range (works with with 'backwards' ranges)"""
    if a<b:
        return range(a,b+1)
    return range(a,b-1,-1)

def diag_range(xy0,xy1):
    """Diagonal range (45 degree diagonal lines)"""
    x0,y0=xy0
    x1,y1=xy1
    dx=1 if x1-x0>0 else -1
    dy=1 if y1-y0>0 else -1
    x,y=x0,y0
    for _ in range(abs(x1-x0)):
        yield x,y
        x+=dx
        y+=dy
    yield x,y

