def step(octos):
    flash_queue, flashed = set(), set()

    for pos in octos.keys():
        octos[pos] += 1
        if octos[pos] > 9:
            flash_queue.add(pos)

    while flash_queue:
        pos = flash_queue.pop()
        flashed.add(pos)
        row, col = pos
        for i in range(row - 1, row + 2):
            for j in range(col - 1, col + 2):
                octos[i, j] += 1
                if octos[i, j] > 9 and (i, j) not in flashed:
                    flash_queue.add((i, j))

    for pos in octos.keys():
        if octos[pos] > 9:
            octos[pos] = 0

    return len(flashed)

