def verify(line):
    opening = {'}': '{', ']': '[', ')': '(', '>': '<'}
    stack = []
    for symbol in line:
        if symbol in '{[(<':
            stack.append(symbol)
        else:
            if not stack or stack[-1] != opening[symbol]:
                return 'CORRUPTED', symbol
            else:
                stack.pop(-1)
    return 'INCOMPLETE', stack

