                    continue
                signature = math.sqrt((b1[0] - b2[0]) ** 2 + (b1[1] - b2[1]) ** 2 + (b1[2] - b2[2]) ** 2)
                signatures.append(signature)
            signatures.sort()
            self.signatures.append(signatures)

