        common_beacons = {}
        for i, my_sig in enumerate(self.signatures):
            for j, other_sig in enumerate(other.signatures):
                count = 0
                if i in common_beacons:
                    break
                for k in range(12):
                    if my_sig[k] == other_sig[k]:
                        count += 1
                if count > 1:
                    common_beacons[i] = j

        if len(common_beacons) < 12:
            return False

        offset = [0, 0, 0]
        axis_map = [0, 1, 2]
        axis_sign = [1, 1, 1]

