    }
    embiggened_grid = [row.copy() for row in grid]
    for iteration in range(4):
        for y in range(len(grid)):
            for x in range(len(grid[0])):
                embiggened_grid[y].append(embiggener[embiggened_grid[y][x + len(grid) * iteration]])

