def find_paths(graph, node, path):
    results = []

    path = path + [node]
    if node == 'end':
        return [path]

    for next in graph[node]:
        if next != 'start':
            if next not in path or next.isupper():
                results.extend(find_paths(graph, next, path))

    return results


def path_me(inputs: dict):
    paths = find_paths(inputs, 'start', [])

    return len(paths)


