        self.buffer = buffer
        self.value = self._evaluate_packet()

    def _evaluate_packet(self):
        version = self.buffer.read(3)
        type = self.buffer.read(3)
        self.version_sum += version

        if type == 4:
            literal_value = ''
            while self.buffer.read(1):
                literal_value += self.buffer.read_str(4)
            literal_value += self.buffer.read_str(4)
