def operate(nums, ops):
    result = nums[0]
    for i in range(len(ops)):
        if ops[i] == '+':
            result += nums[i + 1]
        elif ops[i] == '*':
            result *= nums[i + 1]
        elif ops[i] == '||':
            result = int(str(result) + str(nums[i + 1]))
    return result


def try1(target, numbers):
    n = len(numbers)
    if n == 1:
        return numbers[0] == target
    for operators in product(['+', '*'], repeat=n - 1):
