def sim(r, w, h, t):
    x, y, vx, vy = r
    for _ in range(t):
        x = (x + vx) % w
        y = (y + vy) % h
    return (x, y, vx, vy)

def sim_all(rs, w, h, t):
    return [sim(r, w, h, t) for r in rs]

def vis(r, w, h):
    brd = {(x, y) for x, y, *_ in r}
    for i in range(h):
        for j in range(w):
            if (j, i) in brd:
                print("#", end="")
            else:
                print(".", end="")
        print()

def to_s(r, w, h):
    brd = {(x, y) for x, y, *_ in r}
    lines = []
    for i in range(h):
        line = []
        for j in range(w):
            if (j, i) in brd:
                line.append("#")
            else:
                line.append(".")
        lines.append("".join(line))
    return "\n".join(lines)

