@lru_cache(maxsize=None)
def f(i: str, v: int, d: bool) -> int:
    if i == 'end':
        return 1

    r = 0
    for j in adj[i]:
        if j.isupper(): r += f(j, v, d)
        elif j != 'start':
            seen = v & (1 << idx[j]) != 0
            if not seen or not d:
                r += f(j, v | (1 << idx[j]), seen or d)

    return r


