def explode(a, depth=0):
    if isinstance(a, list):
        if depth == 4:
            return True, a[0], a[1]

        r = explode(a[0], depth+1)
        if r is not None:
            imm, b, c = r
            if imm:
                a[0] = 0

            if isinstance(a[1], int):
                a[1] += c
            else:
                addr(a[1], c)

            c = 0
            return False, b, c

        r = explode(a[1], depth+1)
        if r is not None:
            imm, b, c = r
            if imm:
                a[1] = 0

            if isinstance(a[0], int):
                a[0] += b
            else:
                addl(a[0], b)

            b = 0
            return False, b, c

def split(a):
