Q = [(0, P)]

def push(nd, nstate):
    pd = dist.get(nstate, -1)
    if pd == -1 or nd < pd:
        dist[nstate] = nd
        heappush(Q, (nd, nstate))


def is_correct(rev, x, y):
    c = rev.get((x, y))
    return c is not None and x == dest[c]

