            if instr == 'inp':
                assert False
            else:
                x, y = args
                x = ord(x) - ord('w')
                y = get(y)

                if instr == 'add':
                    vs[x] += y
                elif instr == 'mul':
                    vs[x] *= y
                elif instr == 'div':
