            turn=1

        m= lambda s: re.findall(r'-?\d+',s)
        ignore=False
        xmin,xmax,ymin,ymax,zmin,zmax=list(map(int,m(j)))
        if xmin<-50 or xmax>50 or ymin<-50 or ymax>50 or zmin<-50 or zmax>50:
            ignore=True

        if not ignore:
            for k in range(xmin,xmax+1):
                for l in range(ymin,ymax+1):
