                    shortest(vert, hori, layers - 1) + \
                    (abs(end[1] - start[1]) - 1) * shortest(hori, hori, layers - 1) + \
                    shortest(hori, "A", layers - 1)
                )
    else:
        vert = None
        hori = None
        if end[0] < start[0]:
            vert = "^"
        elif end[0] > start[0]:
            vert = "v"
