#!/usr/bin/env python3

import sys
import rich
from rich import print
import collections
import re
import enum
import dataclasses
from typing import Dict


class Marked(enum.Enum):
    CLEAR = enum.auto()
    MARKED = enum.auto()


@dataclasses.dataclass
class Tile:
    number: int
    row: int
    col: int
    status: Marked


class Board:
    _board_idx = 0

    def __init__(self, tiles):
        self.by_number = {}
        self.by_place = {}
        self.last_guess = None
        self.idx = Board._board_idx
        Board._board_idx += 1
        for tile in tiles:
            self.by_number[tile.number] = tile
            self.by_place[tile.row, tile.col] = tile

    def guess(self, number):
        self.last_guess = number
        if number in self.by_number:
            t = self.by_number[number]
            t.status = Marked.MARKED

    def won(self):
        for pattern in PATTERNS:
            if all(self.by_place[p].status == Marked.MARKED for p in pattern):
                return True
        return False

    def score(self):
        if not self.won():
            raise RuntimeError("Boards only have a score once they've won")
        subscore = sum(
            t.number for t in self.by_number.values() if t.status == Marked.CLEAR
        )
        return self.last_guess * subscore

    def __hash__(self):
        return hash(self.idx)

    def __rich__(self):
        table = rich.table.Table.grid(padding=(0, 1))
        for _ in range(5):
            table.add_column()
        for r in range(5):
            row = []
            for c in range(5):
                t = self.by_place[r, c]
                if t.status == Marked.MARKED:
                    style = "bold"
                else:
                    style = "dim"
                row.append(f"[{style}]{t.number}[/{style}]")
            table.add_row(*row)
        table.add_row()
        return table


PATTERNS = [[(r, c) for r in range(5)] for c in range(5)] + [
    [(r, c) for c in range(5)] for r in range(5)
]


def parse_board(lines):
    assert len(lines) == 5
    tiles = []
    for row_idx, row in enumerate(lines):
        for col_idx, col in enumerate(re.split(" +", row)):
            if col == "":
                continue
            tiles.append(Tile(int(col), row_idx, col_idx, Marked.CLEAR))
    assert len(tiles) == 25
    return Board(tiles)


def parse_problem(lines):
    guesses = [int(n) for n in lines[0].split(",")]

    boards = []
    block = []
    for line in lines[2:]:
        if line == "\n":
            boards.append(parse_board(block))
            block = []
        else:
            block.append(line.strip())

    return guesses, boards


def scores(guesses, boards) -> int:
    won = set()
    for guess in guesses:
        for board in boards:
            board.guess(guess)
        winners = {b for b in boards if b.won()}
        yield from [b.score() for b in winners - won]
        won = winners


with open('year_2021_day_4.txt', "r") as f:
    results = list(scores(*parse_problem(f.readlines())))
    assert results[0] == 4512
    assert results[-1] == 1924

with open('year_2021_day_4.txt', "r") as f:
    results = list(scores(*parse_problem(f.readlines())))
    assert results[0] == 67716
    assert results[-1] == 1830

with open('year_2021_day_4.txt'[1], "r") as f:
    results = list(scores(*parse_problem(f.readlines())))
    print("Score of first winner", results[0])
    print("Score of last winner", results[-1])

import rich
from rich import print
import itertools as it
from typing import Set, List, Iterable, Tuple, FrozenSet


def read_letters(w: str) -> FrozenSet[int]:
    return frozenset(ord(c) - ord("a") for c in w)


def read_line(line) -> Tuple[FrozenSet[FrozenSet[int]], List[FrozenSet[str]]]:
    first, second = line.split(" | ")
    signal_sets = frozenset(read_letters(w) for w in first.strip().split(" "))
    output_sets = [frozenset(w.upper()) for w in second.strip().split(" ")]
    return signal_sets, output_sets


def read(filename):
    with open('year_2021_day_8.txt', "r") as f:
        return [read_line(l) for l in f.readlines()]


def part1(output_sets_list):
    count = 0
    for output_sets in output_sets_list:
        for outputs in output_sets:
            if len(outputs) in [2, 4, 3, 7]:
                count += 1
    return count


_WIRES = list(range(7))

_SEGMENTS = list("ABCDEFG")

_DIGITS = [
    frozenset("ABCEFG"),
    frozenset("CF"),
    frozenset("ACDEG"),
    frozenset("ACDFG"),
    frozenset("BCDF"),
    frozenset("ABDFG"),
    frozenset("ABDEFG"),
    frozenset("ACF"),
    frozenset("ABCDEFG"),
    frozenset("ABCDFG"),
]


def consistent_with_signals(signals: Set[int], digit: Set[str], p: List[str]) -> bool:
    for signal in signals:
        if p[signal] not in digit:
            return False
    return True


def consistent_with_segment_sets(
    jumbled_segment_sets: Iterable[Iterable[str]], p: List[str]
) -> bool:
    return all(
        rerender_jumbled_segments(p, js) in _DIGITS for js in jumbled_segment_sets
    )


def solve(signal_sets: Iterable[Set[int]], segment_sets: Iterable[Set[str]]):
    poss: List[List[str]] = list(list(p) for p in it.permutations(_SEGMENTS))

    # We can reject any possibility that isn't consistent with the
    # digits that we can find becuase their signal-sets have a unqiue
    # size
    for signals in signal_sets:
        if len(signals) == 2:
            poss = [p for p in poss if consistent_with_signals(signals, _DIGITS[1], p)]
        if len(signals) == 4:
            poss = [p for p in poss if consistent_with_signals(signals, _DIGITS[4], p)]
        if len(signals) == 3:
            poss = [p for p in poss if consistent_with_signals(signals, _DIGITS[7], p)]
        if len(signals) == 7:
            poss = [p for p in poss if consistent_with_signals(signals, _DIGITS[8], p)]

    # we can reject any possibility that wouldn't produce a coherent output
    poss = [p for p in poss if consistent_with_segment_sets(segment_sets, p)]

    # some lines are underspecified, but there should still only be a
    # single unique output, because the problem is nice like that
    outputs = {intended_number(p, segment_sets) for p in poss}
    assert len(outputs) == 1

    return poss[0]


_DISPLAY = "\n".join(
    [
        " AAAA ",
        "B    C",
        "B    C",
        " DDDD ",
        "E    F",
        "E    F",
        " GGGG ",
    ]
)


def format_mapping(mapping: List[str]) -> str:
    result = _DISPLAY
    for idx, c in enumerate(mapping):
        result = result.replace(c, str(idx))
    return result


def format_segments(segments: Iterable[str]) -> str:
    result = _DISPLAY
    for seg in "ABCDEFG":
        if seg not in segments:
            result = result.replace(seg, " ")
    return result


def render_signals(mapping: List[str], signals: Iterable[int]) -> Set[str]:
    return {mapping[s] for s in signals}


def unrender_segments(mapping: List[str], segments: Iterable[str]) -> Set[int]:
    revmap = {seg: idx for idx, seg in enumerate(mapping)}
    return {revmap[seg] for seg in segments}


def rerender_jumbled_segments(
    mapping: List[str], jumbled_segments: Iterable[str]
) -> Set[str]:
    intended_signals = unrender_segments(list("ABCDEFG"), jumbled_segments)
    return render_signals(mapping, intended_signals)


def intended_digit(mapping: List[str], jumbled_segments: Iterable[str]) -> int:
    actual_segments = rerender_jumbled_segments(mapping, jumbled_segments)
    return _DIGITS.index(actual_segments)


def intended_number(
    mapping: List[str], jumbled_segment_sets: Iterable[Iterable[str]]
) -> int:
    result = 0
    for jumbled_segments in jumbled_segment_sets:
        result *= 10
        i_d = intended_digit(mapping, jumbled_segments)
        result += i_d
    return result


def hcat(*strs: str) -> str:
    splitted = [s.splitlines() for s in strs]
    result = ""
    for lines in zip(*splitted):
        result += " ".join(lines)
        result += "\n"
    return result


def main():
    ex1 = read("../example1.txt")
    ex2 = read("../example2.txt")
    data = read("../input.txt")
    assert part1([e[1] for e in ex1]) == 0
    assert part1([e[1] for e in ex2]) == 26
    assert part1([e[1] for e in data]) == 412
    ex1_soln = solve(ex1[0][0], ex1[0][1])

    digits = [
        format_segments(rerender_jumbled_segments(ex1_soln, js)) for js in ex1[0][1]
    ]
    print(hcat(format_mapping(ex1_soln), *digits))
    assert intended_number(ex1_soln, ex1[0][1]) == 5353

    assert (
        sum(intended_number(solve(prob[0], prob[1]), prob[1]) for prob in ex2) == 61229
    )

    print(sum(intended_number(solve(prob[0], prob[1]), prob[1]) for prob in data))

import os
from typing import Callable, NewType
import itertools as it


def can(s):
    return "".join(sorted(s))


_DIGITS_TO_SEGMENTS = {
    0: can("abcefg"),
    1: can("cf"),
    2: can("acdeg"),
    3: can("acdfg"),
    4: can("bcdf"),
    5: can("abdfg"),
    6: can("abdefg"),
    7: can("acf"),
    8: can("abcdefg"),
    9: can("abcdfg"),
}

_SEGMENTS_TO_DIGITS = {v: k for k, v in _DIGITS_TO_SEGMENTS.items()}

_UNIQUES = [
    _DIGITS_TO_SEGMENTS[1],
    _DIGITS_TO_SEGMENTS[4],
    _DIGITS_TO_SEGMENTS[7],
    _DIGITS_TO_SEGMENTS[8],
]


def parse(line):
    observed, output = line.strip().split(" | ")
    observed = list(can(s) for s in observed.split(" "))
    output = list(can(s) for s in output.split(" "))
    return observed, output


def part1(observed, output) -> int:
    return sum(len(js) in {2, 3, 4, 7} for js in output)


def unproject(segments_to_signals, output):
    return can(segments_to_signals[js] for js in output)


def part2_apply_mapping(observed, output, segments_to_signals):
    # Given that we can figure out which digits some of the
    # observed signals must produce by looking at their lengths,
    # reject if the mapping fails to produce those digits
    observed_proj = (unproject(segments_to_signals, s) for s in observed)
    for proj in observed_proj:
        for unique in _UNIQUES:
            if len(proj) == len(unique):
                if proj != unique:
                    return None

    # Reject if the mapping doesn't create comprehensible digits
    output_proj = (unproject(segments_to_signals, js) for js in output)
    digits = [_SEGMENTS_TO_DIGITS.get(rp, None) for rp in output_proj]
    if any(d is None for d in digits):
        return None

    # Return what we found
    return int("".join(str(d) for d in digits))


def part2(observed, jumbled_segments) -> int:
    for perm in it.permutations("abcdefg"):
        result = part2_apply_mapping(
            observed, jumbled_segments, dict(zip("abcdefg", perm))
        )
        if result is not None:
            return result
    raise RuntimeError("No solution found")


def read_file(filename: str):
    with open('year_2021_day_8.txt', "r") as f:
        return [parse(s.strip()) for s in f.readlines()]


def solve(data, f) -> int:
    return sum(f(sig, jum) for sig, jum in data)


def main():
    ex1 = read_file("../example1.txt")
    ex2 = read_file("../example2.txt")
    inp = read_file("../input.txt")

    assert solve(ex1, part1) == 0
    assert solve(ex2, part1) == 26
    assert solve(inp, part1) == 412

    assert solve(ex1, part2) == 5353
    assert solve(ex2, part2) == 61229
    assert solve(inp, part2) == 978171

