def get_next_direction(direction):
    if direction == (-1, 0):
        return (0, 1)
    elif direction == (0, 1):
        return (1, 0)
    elif direction == (1, 0):
        return (0, -1)
    else:
        return (-1, 0)


def count_seen_positions(grid, guard_start, direction):
    guard = guard_start
    direction = direction

    seen_states = set()
    seen_positions = set()
    while grid[guard] is not None:
        if (guard, direction) in seen_states:
            return None
        seen_states.add((guard, direction))
        seen_positions.add(guard)
        (i, j) = guard
        (di, dj) = direction
        next_guard = (i + di, j + dj)
        if grid[next_guard] != "#":
            guard = next_guard
        else:
            direction = get_next_direction(direction)

    return len(seen_positions)


