def prev_pos(value, position):
    position = position[:]
    while True:
        if len(position) == 0:
            return None
        if position[-1] == 1:
            position[-1] = 0
            break
        if position[-1] == 0:
            position.pop()
    while True:
        position.append(1)
        if get_at(value, position) is not None:
            continue
        position.pop()
        position.append(0)
        if get_at(value, position) is not None:
            continue
        position.pop()
        return position


def next_pos(value, position):
    position = position[:]
    while True:
        if len(position) == 0:
            return None
        if position[-1] == 0:
            position[-1] = 1
            break
        if position[-1] == 1:
            position.pop()
    while True:
        position.append(0)
        if get_at(value, position) is not None:
            continue
        position.pop()
        position.append(1)
        if get_at(value, position) is not None:
            continue
        position.pop()
        return position


def first_pos(value):
