    while type(get_at(value, position)) != int:
        position.append(0)
    return position


def get_explode(value):
    pos = first_pos(value)
    while pos is not None:
        if len(pos) >= 5:
            return pos[:-1]
        pos = next_pos(value, pos)
    return None


def get_split(value):
