import sys
from collections import defaultdict, Counter

def evolve(fish, days):
	for _ in range(days):
		newfish = defaultdict(int)

		for t, n in fish.items():
			t -= 1

			if t < 0:
				newfish[6] += n
				newfish[8] += n
			else:
				newfish[t] += n

		fish = newfish

	return fish, sum(fish.values())


