import sys
from functools import cache
from math import log10


@cache
def calc(n, blinks=25):
	if blinks == 0:
		return 1

	if n == 0:
		return calc(1, blinks - 1)

	n_digits = int(log10(n)) + 1
	if n_digits % 2 == 0:
		power = 10**(n_digits // 2)
		return calc(n // power, blinks - 1) + calc(n % power, blinks - 1)

	return calc(n * 2024, blinks - 1)


