                        dx, dy, dz = beacon2[0] - beacon1[0], beacon2[1] - beacon1[1], beacon2[2] - beacon1[2]
                        relative = {(x - dx, y - dy, z - dz) for x, y, z in scanner2.beacons}
                        matches = len(root.beacons.intersection(relative))
