                antennas_by_char[char].append((x, y))

    for x, row in enumerate(grid):
        for y, char in enumerate(row):
            if char != '.':
                for eq_pos in antennas_by_char[char]:
                    if (x, y) == eq_pos:
                        continue
                    x_d, y_d = x - eq_pos[0], y - eq_pos[1]
                    for p in [(x, y), eq_pos]:
